%[text] # Comparison
%[text] Direct comparison of static data for ψ = 0° and ψ = 45°.
clear; clc; close all hidden;
%%
%[text] ## Configuration
AXIS = 3; %[control:dropdown:7ac0]{"position":[8,9]}
ALIGNED_FOLDER = "/Users/alexwang/Documents/MATLAB/Linear Traverse/Data/2025_07_15_STAT"; %[control:filebrowser:879a]{"position":[18,89]}
ROTATED_FOLDER = "/Users/alexwang/Documents/MATLAB/Linear Traverse/Data/2025_07_15_STAT"; %[control:filebrowser:0186]{"position":[18,89]}
OUT_FOLDER = "/Users/alexwang/Downloads"; %[control:filebrowser:2fa5]{"position":[14,41]}
MAX = 1; %[control:slider:32c3]{"position":[7,8]}
ERRORBAR = true; %[control:checkbox:3bbe]{"position":[12,16]}
CF_VOLTAGE = 4;
%%
name = Config.NAMES(AXIS);
conv = dictionary(Config.NAMES, ["F_y" "F_x" "F_z" "M_y" "M_x" "M_z"]);
disp_name = conv(name);

out_folder = fullfile(OUT_FOLDER, strjoin(["comparison", "stacked", disp_name], "-"));

if ~exist(out_folder, "dir")
    mkdir(out_folder);
end
%%
%[text] ## FT Comparison
%[text] Plot chosen axis versus distance.
if AXIS <= 3
    DENOMINATOR = Config.W * MAX;
    Process.format_plot("", "Separation, $\Delta z/l$", "Force, $\bar{" + disp_name + "}/W$"); %[output:3cf5a3fc]
else
    DENOMINATOR = Config.W * Config.L * MAX;
    Process.format_plot("", "Separation, $\Delta z/l$", "Moment, $\bar{" + disp_name + "}/(Wl)$");
end

axis("square"); %[output:3cf5a3fc]
xlim([0 8]); %[output:3cf5a3fc]
set(gcf, 'Renderer', 'painters', 'Position', [100 100 1000 750]); %[output:3cf5a3fc]

%% Aligned

load(fullfile(ALIGNED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
static = table2array(results.(name)(:, 2:end)) / DENOMINATOR;

if ERRORBAR == true
    % Plot results (error bars)
    errorbar(SDS, mean(static, 2), std(static, 0, 2), 'bo', 'LineWidth', 1.5); %[output:3cf5a3fc]
else
    % Plot results (data)
    plot(SDS, static, "bx", "MarkerSize", 8, "LineWidth", 1.5);
end

%% Rotated

load(fullfile(ROTATED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
static = table2array(results.(name)(:, 2:end)) / DENOMINATOR;

if ERRORBAR == true
    % Plot results (error bars)
    errorbar(SDS, mean(static, 2), std(static, 0, 2), 'ro', 'LineWidth', 1.5); %[output:3cf5a3fc]
else
    % Plot results (data)
    plot(SDS, static, "rx", "MarkerSize", 8, "LineWidth", 1.5);
end

legend(["Aligned" "Rotated"]); %[output:3cf5a3fc]

%% Save
print(gcf, fullfile(out_folder, "FT.svg"), "-dsvg"); %[output:3cf5a3fc]
savefig(gcf, fullfile(out_folder, "FT.fig"));
%%
%[text] ## Crazyflie Power
figure; %[output:3070f672]
Process.format_plot("", "Separation, $\Delta z/l$", "Power, W"); %[output:3070f672]

axis("square"); %[output:3070f672]
xlim([0 8]); %[output:3070f672]
ylim([5 10]); %[output:3070f672]
set(gcf, 'Renderer', 'painters', 'Position', [100 100 1000 750]); %[output:3070f672]

load(fullfile(ALIGNED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
current = table2array(results.Current(:, 2:end));
power = current * CF_VOLTAGE;

if ERRORBAR == true
    % Plot results (error bars)
    errorbar(SDS, mean(power, 2), std(power, 0, 2), 'bo', 'LineWidth', 1.5); %[output:3070f672]
else
    % Plot results (data)
    plot(SDS, power, "bx", "MarkerSize", 8, "LineWidth", 1.5);
end

load(fullfile(ROTATED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
current = table2array(results.Current(:, 2:end));
power = current * CF_VOLTAGE;

if ERRORBAR == true
    % Plot results (error bars)
    errorbar(SDS, mean(power, 2), std(power, 0, 2), 'ro', 'LineWidth', 1.5); %[output:3070f672]
else
    % Plot results (data)
    plot(SDS, power, "rx", "MarkerSize", 8, "LineWidth", 1.5);
end

legend(["Aligned" "Rotated"]); %[output:3070f672]

%% Save
print(gcf, fullfile(out_folder, "power.svg"), "-dsvg"); %[output:3070f672]
savefig(gcf, fullfile(out_folder, "power.fig"));
%%
%[text] ## Peak Frequencies
figure %[output:6e761c94]
Process.format_plot("", "Separation, $\Delta z/l$", "Audio Peaks, Hz"); %[output:6e761c94]

axis("square"); %[output:6e761c94]
xlim([0 8]); %[output:6e761c94]
set(gcf, 'Renderer', 'painters', 'Position', [100 100 1000 750]); %[output:6e761c94]

% Aligned
load(fullfile(ALIGNED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
first = table2array(results.("First Peak")(:, 2:end));
second = table2array(results.("Second Peak")(:, 2:end));

h1 = scatter(SDS, median(first, 2), "bo", "filled"); %[output:6e761c94]
scatter(SDS, median(second, 2), "bo", "filled"); %[output:6e761c94]

% Rotated
load(fullfile(ROTATED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
first = table2array(results.("First Peak")(:, 2:end));
second = table2array(results.("Second Peak")(:, 2:end));

h3 = scatter(SDS, median(first, 2), "ro", "filled"); %[output:6e761c94]
scatter(SDS, median(second, 2), "ro", "filled"); %[output:6e761c94]

legend([h1, h3], ["Aligned" "Rotated"], 'Location', 'best'); %[output:6e761c94]

%% Save
print(gcf, fullfile(out_folder, "frequency.svg"), "-dsvg"); %[output:6e761c94]
savefig(gcf, fullfile(out_folder, "frequency.fig"));

